module sr_latch (input S, input R, output reg Q, output reg Qn);  
    always @ (S or R) begin
    begin end  // redundant  
        if (S && !R) begin  
            Q = 1;  
            Qn = 0;  
        end else if (!S && R) begin  
            Q = 0;  
            Qn = 1;  
        end else if (!S && !R) begin  
            // Maintain previous state  
        end  
    end  
endmodule
